    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-to-Recipient relationship to a 1:N relationship, enabling multi-recipient shipments. This is a fundamental structural change to a core aggregate that affects data modeling, external integrations, billing, routing, and operational workflows across the entire platform.",
    "bounded_context": "Shipment Management / Fulfillment",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from an origin to one or more destinations. The root aggregate in this bounded context." },
      { "term": "Recipient", "definition": "A person or entity designated to receive a delivery. Has a name, address, phone number, and (under the new model) individual delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how and when a delivery should be made (e.g., time windows, signature requirements, safe-place instructions, contactless delivery)." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with more than one recipient, where each recipient may have a distinct delivery address and distinct delivery preferences." },
      { "term": "Primary Recipient", "definition": "An as-yet-undefined concept that may be needed to preserve backward compatibility and designate a default or canonical recipient for a multi-recipient shipment." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a shipment. Under multi-recipient, status semantics become complex — a shipment may be partially delivered." },
      { "term": "Partner API", "definition": "External integration contracts that currently consume shipment data in a single-recipient format." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient. Zero-recipient shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient has no delivery destination and is physically meaningless — it cannot be routed, delivered, or tracked.",
      "testable_assertion": "Creating or updating a Shipment with an empty Recipients collection must fail validation."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically execute a delivery: address for routing, name for identification, phone for contact on delivery day.",
      "testable_assertion": "Adding a Recipient missing any of name, address, or phone must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment may have independent delivery preferences.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a policy/feature layer. A VP could decide all recipients on a shared shipment inherit the same preferences. The system must support per-recipient preferences but this is configurable behavior.",
      "testable_assertion": "Two Recipients on the same Shipment can be persisted with different delivery preference values."
    },
    {
      "id": "BR-4",
      "rule": "All existing single-recipient shipments must remain valid and queryable after migration without data loss or semantic change.",
      "invariant": true,
      "invariant_justification": "2 million shipments in production represent fulfilled or in-flight business commitments. Corrupting or losing this data violates contractual and operational integrity.",
      "testable_assertion": "After migration, querying any pre-existing shipment returns exactly the same recipient data (name, address, phone) as before."
    },
    {
      "id": "BR-5",
      "rule": "External partner APIs must continue to receive shipment data they can parse, either through the existing single-recipient format or via a versioned contract.",
      "invariant": true,
      "invariant_justification": "Breaking partner integrations causes immediate operational failure — parcels stop flowing, SLAs are breached, and contractual penalties may apply.",
      "testable_assertion": "Partner API payloads for single-recipient shipments remain structurally identical to the current format. Multi-recipient shipments are either represented via a new API version or a well-defined mapping."
    },
    {
      "id": "BR-6",
      "rule": "Shipment-level status must have a defined relationship to per-recipient delivery outcomes when recipients have different delivery results.",
      "invariant": false,
      "invariant_justification": "Status rollup policy is a business decision (e.g., 'delivered' when all recipients received, or 'partially delivered' as a new state). This is policy, not physics.",
      "testable_assertion": "When 2 of 3 recipients have been delivered and 1 has failed, the shipment status reflects the defined rollup policy (not an undefined state)."
    },
    {
      "id": "BR-7",
      "rule": "Billing for a multi-recipient shipment must have a defined model — whether it is billed as one shipment, per-recipient, or via another scheme.",
      "invariant": false,
      "invariant_justification": "Pricing is a business policy. But it must be explicitly defined before multi-recipient shipments go live, because charging nothing or the wrong amount is a financial loss.",
      "testable_assertion": "A multi-recipient shipment generates an invoice line item consistent with the chosen billing model."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new shipment is being created",
      "when": "the caller provides one or more recipients, each with name, address, phone, and optional delivery preferences",
      "then": "the shipment is persisted with all recipients and their individual preferences"
    },
    {
      "id": "AC-2",
      "given": "A new shipment is being created",
      "when": "the caller provides zero recipients",
      "then": "the system rejects the request with a validation error"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient shipment created before the migration",
      "when": "it is queried via the API",
      "then": "it returns the recipient in the new collection format with all original data intact (name, address, phone)"
    },
    {
      "id": "AC-4",
      "given": "An external partner integration receives a shipment payload",
      "when": "the shipment has exactly one recipient",
      "then": "the payload matches the legacy single-recipient format (backward compatible)"
    },
    {
      "id": "AC-5",
      "given": "An external partner integration receives a multi-recipient shipment payload",
      "when": "the partner has not opted into the new API version",
      "then": "the system applies a defined fallback strategy (e.g., sends only the primary recipient, or rejects with an informative error)"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient shipment where one recipient's delivery fails and others succeed",
      "when": "the shipment status is queried",
      "then": "the status accurately reflects the partial delivery state per the defined rollup policy"
    },
    {
      "id": "AC-7",
      "given": "A recipient is added to or removed from an existing shipment",
      "when": "the modification would result in zero recipients",
      "then": "the system rejects the removal, preserving the minimum-one-recipient invariant"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient shipment where two recipients share the same address",
      "expected_behavior": "Both recipients are stored independently. The system does not deduplicate by address — recipients are distinct entities even at the same location (e.g., two tenants in the same building)."
    },
    {
      "scenario": "A courier arrives to deliver to Recipient A but Recipient B's delivery preference says 'deliver only after 6pm' at a different address",
      "expected_behavior": "Each recipient's delivery is independently fulfillable. Route optimization must treat each recipient as a separate stop with its own constraints."
    },
    {
      "scenario": "Partner API receives a webhook for a shipment that was single-recipient but had a second recipient added after initial creation",
      "expected_behavior": "The partner receives an update event. If the partner is on the legacy API version, the fallback strategy defined in AC-5 applies."
    },
    {
      "scenario": "Migration of 2 million existing shipments — a recipient record has a NULL phone number due to legacy data quality issues",
      "expected_behavior": "Migration must handle dirty data gracefully. Either backfill with a sentinel value and flag for review, or apply a data cleansing step before migration. The migration must not silently drop records."
    },
    {
      "scenario": "A shipment is cancelled — does cancellation apply to all recipients or can individual recipients be cancelled?",
      "expected_behavior": "This must be explicitly defined. Per-recipient cancellation introduces a 'partially cancelled' state that affects billing, notifications, and courier dispatch."
    },
    {
      "scenario": "Reporting and analytics queries that assume one recipient per shipment (e.g., 'shipments by region')",
      "expected_behavior": "Queries must be updated. A multi-recipient shipment spanning two regions should appear in both region counts, or reporting must define how to attribute multi-region shipments."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments unlock new revenue streams (bulk/split shipments, gift-to-many use cases) but require a defined billing model. Incorrect billing logic could cause revenue leakage. Migration itself carries cost in engineering time and potential downtime. Partner API breakage could trigger SLA penalties.",
    "operational": "Significant operational complexity increase: route optimization must handle multiple stops per shipment, courier apps must display per-recipient delivery flows, dispatch logic changes, status tracking becomes multi-dimensional. The 2M row migration requires a careful rollout strategy (likely dual-write or progressive migration) to avoid downtime.",
    "user": "End users gain the ability to send to multiple recipients in a single shipment — a high-value feature for corporate, e-commerce, and gift use cases. However, the UX must clearly communicate per-recipient status and preferences, or users will be confused by partial delivery states.",
    "risk": "HIGH. This touches a core aggregate boundary. Risks include: (1) data migration failure or corruption of 2M records, (2) partner API breakage causing operational disruption, (3) undefined status semantics leading to inconsistent tracking, (4) billing model gaps causing revenue loss, (5) downstream systems (notifications, analytics, dispatch) that assume 1:1 relationship breaking silently.",
    "stakeholders_affected": [
      { "group": "End Users / Shippers", "impact": "Gain multi-recipient capability but face UX complexity for tracking and managing per-recipient outcomes." },
      { "group": "Recipients", "impact": "May receive delivery preference options they didn't have before. Must be notified independently per their preferences." },
      { "group": "Couriers / Drivers", "impact": "Workflow changes — a single shipment now means potentially multiple stops with different instructions. App UX must clearly separate per-recipient tasks." },
      { "group": "External Partners", "impact": "API contract change. Partners on legacy integrations risk breakage unless backward compatibility or versioning is implemented." },
      { "group": "Finance / Billing", "impact": "Must define and implement a billing model for multi-recipient shipments before launch." },
      { "group": "Operations / Dispatch", "impact": "Route optimization algorithms must be updated. Dispatch logic for assigning shipments to couriers changes when a shipment has multiple geographically dispersed stops." },
      { "group": "Customer Support", "impact": "Must be trained on new shipment states (partial delivery, per-recipient issues). Support tooling must surface per-recipient detail." }
